<template>
  <div class="tracker-div">
    <div>
      <TrackerNewCategory v-on:add-new-category="handleNewCategory"/>
    </div>
    <div v-bind:key="category.id" v-for="category in categories">
      <h3>
          <TrackerCategory v-bind:category="category" v-bind:items="items"
          v-on:remove-category="handleRemoveCategory"
          v-on:remove-item="handleRemoveItem"
          v-on:item-add-good="handleAddGood"
          v-on:item-add-bad="handleAddBad"
          v-on:add-new-item="handleNewItem"
          v-on:item-reset-count="handleResetCount"
          v-on:category-title-changed="handleCategoryTitleChanged"
          v-on:item-title-changed="handleItemTitleChanged"/>
      </h3>
    </div>
  </div>




</template>


<script>

import TrackerCategory from './TrackerCategory.vue'
import TrackerNewCategory from './TrackerNewCategory.vue'

export default {
  name:"Tracker",
  components: {
      TrackerCategory,
      TrackerNewCategory
  },
  methods:{
    handleNewCategory: function( newCategory ){
      this.categories = [...this.categories, newCategory];
    },
    handleNewItem: function( newItem ){
      this.items = [...this.items, newItem];
    },
    handleRemoveCategory: function( id ){
      this.categories = this.categories.filter( category => category.id !== id );
      this.items = this.items.filter( item => item.category !== id );
    },
    handleRemoveItem: function( id ){
      this.items = this.items.filter( item => item.id !== id );
    },
    handleAddGood: function( id ){
      var itemIndex = this.getItemIndexFromId( id );
      var item = this.items[ itemIndex ];
      item.goodCount++;
      this.items.splice( itemIndex, 1, item);
    },
    handleAddBad: function( id ){
      var itemIndex = this.getItemIndexFromId( id );
      var item = this.items[ itemIndex ];
      item.badCount++;
      this.items.splice( itemIndex, 1, item);
    },
    handleItemTitleChanged: function( id ){
      var itemIndex = this.getItemIndexFromId( id );
      var item = this.items[ itemIndex ];
      this.items.splice( itemIndex, 1, item);
    },
    handleCategoryTitleChanged: function( id ){
      var categoryIndex = this.getCategoryIndexFromId( id );
      var category = this.categories[ categoryIndex ];
      this.categories.splice( categoryIndex, 1, category);
    },
    handleResetCount: function( id ){
      var itemIndex = this.getItemIndexFromId( id );
      var item = this.items[ itemIndex ];
      item.badCount = 0;
      item.goodCount = 0;
      this.items.splice( itemIndex, 1, item);
    },
    getItemIndexFromId: function( id ){
      return this.items.findIndex( item => item.id === id );
    },
    getCategoryIndexFromId: function( id ){
      return this.categories.findIndex( category => category.id === id );
    },
    saveItems: function(){
      const parsed = JSON.stringify( this.items );
      localStorage.setItem('items', parsed);
    },
    saveCategories: function(){
      const parsed = JSON.stringify( this.categories );
      localStorage.setItem('categories', parsed);
    }
  },
  data() {
    return {
      items: [
          {
            category: 1,
            id: 2,
            title: "Demo",
            goodCount: 0,
            badCount: 0
          }
      ],
      categories: [
          {
            id: 1,
            title: "Test category"
          }
      ]
    }
  },
  mounted(){
    if( localStorage.getItem('items')){
      try{
        this.items = JSON.parse( localStorage.getItem('items') );
      }
      catch( e )
      {
        localStorage.removeItem( 'items' );
      }
    }

    if( localStorage.getItem('categories')){
      try{
        this.categories = JSON.parse( localStorage.getItem('categories') );
      }
      catch( e )
      {
        localStorage.removeItem( 'categories' );
      }
    }
  },
  watch:{
    items(){
      this.saveItems();
    },
    categories(){
      this.saveCategories();
    }
  }
}
</script>


<style scoped>
  .tracker-div{
    margin: auto;
    border: 2px solid;
  }
</style>