<template>
  <div>
    <div class="tracker-category">
        <TrackerCategoryName class="category-name" v-bind:category="category" v-on:title-changed="handleTitleChanged" />
        <div class="tracker-right-column">
          <CopyButton class="picture-button" v-on:copy="handleCopy"/>
          <RemoveButton class="picture-button" v-on:remove="handleRemoveCategory"/>
        </div>
    </div>
    <div v-bind:key="item.id" v-for="item in items">
        <h3>
            <TrackerItem v-bind:item="item" v-if="item.category === category.id"
            v-on:remove="handleRemoveItem"
            v-on:add-good="handleAddGood"
            v-on:add-bad="handleAddBad"
            v-on:reset="handleResetCount"
            v-on:title-changed="handleItemTitleChanged"/>
        </h3>
    </div>
    <TrackerNewItem class="tracker-new-item" v-on:add-new-item="handleNewItem"/>
  </div>
  
</template>


<script>

import TrackerItem from "./TrackerItem.vue"
import TrackerCategoryName from "./TrackerCategoryName.vue"
import TrackerNewItem from "./TrackerNewItem.vue"
import RemoveButton from "./general/RemoveButton.vue"
import CopyButton from "./general/CopyButton.vue"

export default {
  name:"TrackerCategory",
  components:{
    TrackerCategoryName,
    TrackerNewItem,
    RemoveButton,
    CopyButton,
    TrackerItem
  },
  props: ["category","items"],
  methods:{
    handleNewItem: function( newItem ){
      newItem.category = this.category.id;
      this.$emit( 'add-new-item', newItem );
    },
    handleRemoveCategory: function(){
      this.$emit( 'remove-category', this.category.id );
    },
    handleTitleChanged: function(){
      this.$emit( 'category-title-changed', this.category.id );
    },
    handleCopy: function(){
      var str = this.category.title;
      this.items.forEach(item => {
        if ( item.category === this.category.id )
        {
          str += '\n' + item.title + " - " + this.getPercentage( item );
        }
      });
      const el = document.createElement('textarea');
      el.value = str;
      document.body.appendChild(el);
      el.select();
      document.execCommand('copy');
      document.body.removeChild(el);
    },
    handleRemoveItem: function( id ){
      this.$emit( 'remove-item', id );
    },
    handleAddGood: function( id ){
      this.$emit( 'item-add-good', id );
    },
    handleAddBad: function( id ){
      this.$emit( 'item-add-bad', id );
    },
    handleResetCount: function( id ){
      this.$emit( 'item-reset-count', id );
    },
    handleItemTitleChanged: function( id ){
      this.$emit( 'item-title-changed', id );
    },
    getPercentage: function( item ){
      if( ( item.goodCount + item.badCount ) == 0 ) return "0%"
      var percent = item.goodCount / ( item.goodCount + item.badCount );
      percent = (percent * 100).toFixed(0);
      return percent + "%";
    }
  }

}
</script>


<style scoped>

  .tracker-category{
    background: #f4f4f4;
    display:flex;
  }

  .category-name{
    flex:auto;
    padding: 0px;
    overflow: hidden !important;
    text-overflow: ellipsis;
    display: -webkit-box;
  }

  .picture-button{
    flex-shrink:0;
  }

  .tracker-new-item{
    padding-left:15px;
  }
</style>